 #[derive(Debug)]
 pub enum AgentError {
     InvalidAgentId(String),
     Io(std::io::Error),
     ProcessFailed {
         program: PathBuf,
         status: Option<i32>,
         stderr: String,
     },
     UnknownSession(AgentId),
+    UnsupportedAgentCommand {
+        agent_id: AgentId,
+        command: String,
+    },
 }

 impl fmt::Display for AgentError {
     fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
         match self {
             Self::InvalidAgentId(message) => formatter.write_str(message),
             Self::Io(error) => write!(formatter, "{error}"),
             Self::ProcessFailed {
                 program,
                 status,
                 stderr,
             } => write!(
                 formatter,
                 "{} failed with status {:?}: {}",
                 program.display(),
                 status,
                 stderr.trim()
             ),
             Self::UnknownSession(id) => write!(formatter, "unknown agent session `{id}`"),
+            Self::UnsupportedAgentCommand { agent_id, command } => write!(
+                formatter,
+                "backend command `{command}` is not supported for agent session `{agent_id}`"
+            ),
         }
     }
 }

 impl std::error::Error for AgentError {
     fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
         match self {
             Self::Io(error) => Some(error),
             _ => None,
         }
     }
 }

 impl From<std::io::Error> for AgentError {
     fn from(error: std::io::Error) -> Self {
         Self::Io(error)
     }
 }
