+pub(crate) fn agent_backend_command_text(message: &str) -> Option<&str> {
+    let trimmed = message.trim();
+    let rest = trimmed.strip_prefix('/')?;
+    rest.chars()
+        .next()
+        .is_some_and(|ch| !ch.is_whitespace())
+        .then_some(trimmed)
+}
