368	    fn run_invocation_streaming(
369	        &self,
370	        invocation: &CodexInvocation,
371	        agent_id: Option<&AgentId>,
372	        sink: &mut dyn FnMut(AgentStreamEvent),
373	    ) -> Result<String, AgentError> {
374	        let mut command = Command::new(&invocation.program);
375	        command
376	            .args(&invocation.args)
377	            .stdin(Stdio::piped())
378	            .stdout(Stdio::piped())
379	            .stderr(Stdio::piped());
380	        configure_agent_child_process(&mut command);
381	        let mut child = command.spawn()?;
382	        let child_pid = child.id();
383	        let _process_guard = self.shutdown.register(child.id());
384	        if let Some(agent_id) = agent_id {
385	            self.state
386	                .lock()
387	                .expect("codex backend state mutex poisoned")
388	                .active_processes
389	                .insert(agent_id.clone(), child_pid);
390	        }
391	
392	        if let Some(stdin) = child.stdin.as_mut() {
393	            stdin.write_all(invocation.stdin.as_bytes())?;
394	        }
395	        drop(child.stdin.take());
396	
397	        let stderr_reader = child.stderr.take().map(|mut stderr| {
398	            thread::spawn(move || {
399	                let mut text = String::new();
400	                let _ = stderr.read_to_string(&mut text);
401	                text
402	            })
403	        });
404	
405	        let mut stdout_text = String::new();
406	        if let Some(stdout) = child.stdout.take() {
407	            for line in BufReader::new(stdout).lines() {
408	                let line = line?;
409	                if let Some(event) = codex_stream_event(&line) {
410	                    sink(event);
411	                }
412	                stdout_text.push_str(&line);
413	                stdout_text.push('\n');
414	            }
415	        }
416	
417	        let status = child.wait()?;
418	        if let Some(agent_id) = agent_id {
419	            let mut state = self
420	                .state
421	                .lock()
422	                .expect("codex backend state mutex poisoned");
423	            if state
424	                .active_processes
425	                .get(agent_id)
426	                .is_some_and(|pid| *pid == child_pid)
427	            {
428	                state.active_processes.remove(agent_id);
429	            }
430	        }
431	        let stderr = stderr_reader
432	            .and_then(|reader| reader.join().ok())
433	            .unwrap_or_default();
434	
435	        if status.success() {
436	            Ok(stdout_text.trim().to_string())
437	        } else {
438	            Err(AgentError::ProcessFailed {
439	                program: invocation.program.clone(),
440	                status: status.code(),
441	                stderr: process_failure_output(stderr, &stdout_text),
442	            })
443	        }
444	    }
445	}
