546	            let message = ChatMessage::new(MessageRole::Agent, text);
547	            self.record_agent_exchange(agent_id, command, message.clone())?;
548	            return Ok(message);
549	        }
550	
551	        let invocation = self.build_command_invocation(agent_id, command)?;
552	        let output = self.run_invocation_streaming(&invocation, Some(agent_id), sink)?;
553	        let reply = parse_codex_output(&output).agent_reply.unwrap_or(output);
554	        let message = ChatMessage::new(MessageRole::Agent, reply);
555	        self.record_agent_exchange(agent_id, command, message.clone())?;
556	        Ok(message)
557	    }
