585	fn parse_codex_output(output: &str) -> ParsedCodexOutput {
586	    let mut parsed = ParsedCodexOutput::default();
587	    for line in output.lines() {
588	        let compact = compact_json_line(line);
589	        if compact.contains(r#""type":"thread.started""#) {
590	            parsed.thread_id = json_string_field(&compact, "thread_id").or(parsed.thread_id);
591	        }
592	        if compact.contains(r#""type":"item.completed""#)
593	            && compact.contains(r#""type":"agent_message""#)
594	            && let Some(text) = json_string_field(&compact, "text")
595	        {
596	            append_agent_reply(&mut parsed.agent_reply, text);
597	        }
598	    }
599	    parsed
600	}
