602	fn append_agent_reply(reply: &mut Option<String>, text: String) {
603	    match reply {
604	        Some(existing) if !existing.is_empty() && !text.is_empty() => {
605	            existing.push_str("\n\n");
606	            existing.push_str(&text);
607	        }
608	        Some(existing) => existing.push_str(&text),
609	        None => *reply = Some(text),
610	    }
611	}
