613	fn codex_stream_event(line: &str) -> Option<AgentStreamEvent> {
614	    let compact = compact_json_line(line);
615	    if compact.contains(r#""type":"item.completed""#)
616	        && compact.contains(r#""type":"agent_message""#)
617	    {
618	        return json_string_field(&compact, "text").map(AgentStreamEvent::AgentMessage);
619	    }
620	    if compact.contains(r#""type":"error""#) {
621	        return json_string_field(&compact, "message").map(AgentStreamEvent::Error);
622	    }
623	    if compact.contains(r#""type":"thread.started""#) {
624	        return json_string_field(&compact, "thread_id")
625	            .map(|thread_id| AgentStreamEvent::Status(format!("Codex session {thread_id}")));
626	    }
627	    if compact.contains(r#""type":"turn.started""#) {
628	        return Some(AgentStreamEvent::Status("Codex is working".to_string()));
629	    }
630	    None
631	}
